    'zr_cp_footer_menu_zr_title': 'Tutorial Live Dealer',
    'zr_cp_footer_menu_zr_menus_0': 'Peraturan Permainan',
    'zr_cp_footer_menu_zr_menus_1': 'Peraturan Pengedaran Kad',
    'zr_cp_footer_menu_zr_menus_2': 'Pengiraan Mata',
