    'zr_cp_footer_menu_zr_title': 'دليل اللعب المباشر',
    'zr_cp_footer_menu_zr_menus_0': 'قواعد اللعبة',
    'zr_cp_footer_menu_zr_menus_1': 'قواعد توزيع البطاقات',
    'zr_cp_footer_menu_zr_menus_2': 'حساب النقاط',
    'zr_cp_footer_menu_zr_menus_3': 'تحديد اللعب',
    'zr_cp_footer_menu_zr_menus_4': 'جدول الاحتمالات',
    'zr_cp_footer_menu_zr_menus_5': 'ميزات اللعبة',
    'zr_cp_footer_menu_zr_menus_6': 'ملاحظات هامة',
    'zr_cp_footer_menu_zr_numbers_0': '0',
    'zr_cp_footer_menu_zr_numbers_1': '1',
    'zr_cp_footer_menu_zr_numbers_2': '2',
    'zr_cp_footer_menu_zr_numbers_3': '3',
    'zr_cp_footer_menu_zr_numbers_4': '4',
    'zr_cp_footer_menu_zr_numbers_5': '5',
    'zr_cp_footer_menu_zr_numbers_6': '6',
    'zr_cp_footer_menu_zr_numbers_7': '7',
    'zr_cp_footer_menu_zr_numbers_8': '8',
    'zr_cp_footer_menu_zr_numbers_9': '9',
    'zr_cp_footer_menu_zr_numbers_10': '10',
    'zr_cp_footer_menu_zr_point': 'النقاط',
    'zr_cp_footer_menu_zr_zrtext_0_0':
        'يستخدم 8 مجموعات من البطاقات (باستثناء الجوكر)، بإجمالي 416 بطاقة؛',
    'zr_cp_footer_menu_zr_zrtext_0_1':
        'يتلقى كل من "اللاعب" و"البنك" بطاقتين، "اللاعب" أولاً ثم "البنك" (نفس ترتيب توزيع البطاقات). إذا لم يتم تحديد الفائز في الجولة الأولى، يتم توزيع بطاقات إضافية وفقًا لـ"قواعد توزيع البطاقات"، مع حد أقصى من بطاقة واحدة لكل جانب لتحديد النتيجة.',
    'zr_cp_footer_menu_zr_zrtext_0_2':
        'إذا حصل أي طرف على 8 أو 9 نقاط (فائز طبيعي)، يتم تسوية الجولة باستخدام أول 4 بطاقات ولا يتم سحب المزيد من البطاقات؛',
    'zr_cp_footer_menu_zr_zrtext_0_3':
        'يتم تحديد النتيجة النهائية بمقارنة رقم الآحاد من إجمالي النقاط بين اللاعب والمصرفي.',
    'zr_cp_footer_menu_zr_zrtext_1_title':
        'بعد توزيع البطاقات الأولى على اللاعب والمصرفي، قم بتحديد ما إذا كانت هناك حاجة لسحب المزيد من البطاقات. تحقق من اللاعب أولاً، ثم المصرفي. ارجع إلى الجدول أدناه:',
    'zr_cp_footer_menu_zr_zrtext_1_title1': 'سحب بطاقات اللاعب',
    'zr_cp_footer_menu_zr_zrtext_1_title2': 'سحب البنك',
    'zr_cp_footer_menu_zr_zrtext_1_contents0': 'إجمالي نقاط اللاعب',
    'zr_cp_footer_menu_zr_zrtext_1_contents1': 'يجب سحب البطاقات',
    'zr_cp_footer_menu_zr_zrtext_1_contents2': 'يجب عدم سحب البطاقات',
    'zr_cp_footer_menu_zr_zrtext_1_contents3': 'الفوز الطبيعي، تحديد النتيجة',
    'zr_cp_footer_menu_zr_zrtext_1_contents4': 'يجب سحب البطاقات',
    'zr_cp_footer_menu_zr_zrtext_1_contents5':
        'إذا سحب اللاعب بطاقة ثالثة بقيمة 8، لا يسحب البنك بطاقة أخرى',
    'zr_cp_footer_menu_zr_zrtext_1_contents6':
        'إذا سحب اللاعب بطاقة ثالثة بقيمة 0، 1، 8، أو 9، لا يسحب البنك بطاقة أخرى',
    'zr_cp_footer_menu_zr_zrtext_1_contents7':
        'إذا سحب اللاعب بطاقة ثالثة بقيمة 0، 1، 2، 3، 8، أو 9، لا يسحب البنك بطاقة أخرى',
    'zr_cp_footer_menu_zr_zrtext_1_contents8':
        'إذا سحب اللاعب بطاقة ثالثة بقيمة 6 أو 7، يجب أن يسحب البنك بطاقة أخرى',
    'zr_cp_footer_menu_zr_zrtext_2_contents0':
        'النقاط من A-9، محسوبة على أساس قيمة البطاقة، حيث تعادل A نقطة واحدة.',
    'zr_cp_footer_menu_zr_zrtext_2_contents1': '10 أو J أو Q أو K تساوي 0 نقاط',
    'zr_cp_footer_menu_zr_zrtext_2_contents2': 'مثال',
    'zr_cp_footer_menu_zr_zrtext_2_contents3': '+',
    'zr_cp_footer_menu_zr_zrtext_3_contents0': 'المصرفي & اللاعب & التعادل',
    'zr_cp_footer_menu_zr_zrtext_3_contents1':
        'إذا كانت نقاط المصرفي أعلى من نقاط اللاعب، فإن من يراهن على "المصرفي" يحصل على المكافأة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents2': 'مثال',
    'zr_cp_footer_menu_zr_zrtext_3_contents3': 'المصرفي:',
    'zr_cp_footer_menu_zr_zrtext_3_contents4': 'اللاعب:',
    'zr_cp_footer_menu_zr_zrtext_3_contents5':
        'إذا كانت نقاط اللاعب أعلى من نقاط المصرفي، فإن من يراهن على "اللاعب" يحصل على المكافأة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents6':
        'إذا كانت نقاط المصرفي واللاعب متساوية، فإن من يراهن على "التعادل" يحصل على المكافأة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents7': 'زوج المصرفي & زوج اللاعب',
    'zr_cp_footer_menu_zr_zrtext_3_contents8':
        'في الجولة الحالية، إذا كانت أول ورقتين من المصرفي أو اللاعب تشكلان زوجًا (فقط الأرقام أو الحروف، ولا يحسب الرموز)؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents9': 'البنك / اللاعب:',
    'zr_cp_footer_menu_zr_zrtext_3_contents10':
        'إذا كان أول ورقتين في البنك هو زوج، فإن ذلك يسمى "زوج البنك". وإذا كان أول ورقتين في اللاعب هو زوج، فإن ذلك يسمى "زوج اللاعب".',
    'zr_cp_footer_menu_zr_zrtext_3_contents11':
        'عند ظهور زوج، يتم منح المكافأة للمراهن على "زوج البنك" أو "زوج اللاعب" وفقاً للاحتمالات المحددة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents12': '3. أي زوج',
    'zr_cp_footer_menu_zr_zrtext_3_contents13':
        'يشير إلى أن أول ورقتين في البنك أو اللاعب يشكلان زوجاً (راجع زوج البنك & زوج اللاعب)؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents14':
        'سواء ظهر زوج البنك أو زوج اللاعب، يحصل المراهن على "أي زوج" على المكافأة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents15': '4. الزوج المثالي',
    'zr_cp_footer_menu_zr_zrtext_3_contents16':
        'يشير إلى أن أول ورقتين من يد المصرفي أو اللاعب هما زوج (انظر زوج المصرفي وزوج اللاعب) بشرط أن تكون الأوراق من نفس النوع؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents17':
        'بغض النظر عما إذا كان المصرفي أو اللاعب يملكان زوجًا مثاليًا، فإن من يراهن على "الزوج المثالي" سيحصل على المكافأة المقابلة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents18': '5. الزوج الفائق',
    'zr_cp_footer_menu_zr_zrtext_3_contents19':
        'في أول أربع ورقات، تحتوي اليد على ورقتين أو أكثر بنفس القيمة (بغض النظر عن النوع).',
    'zr_cp_footer_menu_zr_zrtext_3_contents20': '6. التنين 7',
    'zr_cp_footer_menu_zr_zrtext_3_contents21':
        'يفوز المصرفي بثلاث أوراق يبلغ مجموعها 7 نقاط.',
    'zr_cp_footer_menu_zr_zrtext_3_contents22': '7. باندا 8',
    'zr_cp_footer_menu_zr_zrtext_3_contents23':
        'يفوز المصرفي بثلاث أوراق يبلغ مجموعها 8 نقاط.',
    'zr_cp_footer_menu_zr_zrtext_3_contents24':
        '8. النمر الكبير & النمر الصغير',
    'zr_cp_footer_menu_zr_zrtext_3_contents25':
        'يفوز المصرفي بثلاث أوراق يبلغ مجموعها 6 نقاط ويُعتبر النمر الكبير؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents26':
        'المصرفي يفوز ببطاقتين بمجموع 6 نقاط كالـ"النمر الصغير".',
    'zr_cp_footer_menu_zr_zrtext_3_contents27': '9. تعادل النمر',
    'zr_cp_footer_menu_zr_zrtext_3_contents28':
        'يتعادل المصرفي واللاعب بمجموع 6 نقاط.',
    'zr_cp_footer_menu_zr_zrtext_3_contents29': '10. زوج النمر',
    'zr_cp_footer_menu_zr_zrtext_3_contents30':
        'بناءً على نتائج أول أربع بطاقات من المصرفي واللاعب، إذا تحقق أحد النتائج الثلاث التالية، يتم منح مكافآت مختلفة:',
    'zr_cp_footer_menu_zr_zrtext_3_contents31':
        'زوج من المصرفي واللاعب، وتكون البطاقات متطابقة في الرقم.',
    'zr_cp_footer_menu_zr_zrtext_3_contents32': 'زوج من المصرفي واللاعب.',
    'zr_cp_footer_menu_zr_zrtext_3_contents33': 'زوج من المصرفي واللاعب.',
    'zr_cp_footer_menu_zr_zrtext_3_contents34':
        'لن يتم إعادة الرهانات على التعادل.',
    'zr_cp_footer_menu_zr_zrtext_3_contents35':
        '11. بطاقات السماء للمصرفي & بطاقات السماء للاعب',
    'zr_cp_footer_menu_zr_zrtext_3_contents36':
        'إذا كانت أول ورقتين للمصرف تساوي 8 أو 9 نقاط وفاز المصرف، يحصل المراهنون على "بطاقة السماء للمصرف" على مكافأة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents37':
        'إذا كانت أول ورقتين للعميل تساوي 8 أو 9 نقاط وفاز العميل، يحصل المراهنون على "بطاقة السماء للعميل" على مكافأة.',
    'zr_cp_footer_menu_zr_zrtext_3_contents38': '12. بطاقة السماء',
    'zr_cp_footer_menu_zr_zrtext_3_contents39':
        'إذا كانت أول ورقتين للمصرف أو العميل تساوي 8 أو 9 نقاط، يفوز اللاعب على الفور.',
    'zr_cp_footer_menu_zr_zrtext_3_contents40': '13. التنين والنمر والتعادل',
    'zr_cp_footer_menu_zr_zrtext_3_contents41':
        'إذا كانت قيمة أول ورقة للمصرف أكبر من قيمة أول ورقة للعميل (القيم 10، J، Q، K تساوي 10، 11، 12، 13 نقطة)، يفوز التنين;',
    'zr_cp_footer_menu_zr_zrtext_3_contents42':
        'إذا كانت قيمة أول ورقة للعميل أكبر من قيمة أول ورقة للمصرف (القيم 10، J، Q، K تساوي 10، 11، 12، 13 نقطة)، يفوز النمر;',
    'zr_cp_footer_menu_zr_zrtext_3_contents43':
        'إذا كانت قيمة أول ورقة للمصرف والعميل متساوية (القيم 10، J، Q، K تساوي 10، 11، 12، 13 نقطة)، يكون التعادل بين التنين والنمر.',
    'zr_cp_footer_menu_zr_zrtext_3_contents44': '14. سوبر سيكس',
    'zr_cp_footer_menu_zr_zrtext_3_contents45':
        'يمكن المراهنة في الوضعين الخالي من العمولة ومع العمولة؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents46':
        'إذا لم يسحب المصرفي بطاقة، وكان المجموع النهائي 6، وكانت النقاط أكبر من اللاعب، يتم دفع 12 ضعف؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents47':
        'إذا سحب المصرفي بطاقة، وكان المجموع النهائي 6، وكانت النقاط أكبر من اللاعب، يتم دفع 20 ضعف.',
    'zr_cp_footer_menu_zr_zrtext_3_contents48':
        '15. تنين المصرفي & تنين اللاعب',
    'zr_cp_footer_menu_zr_zrtext_3_contents49':
        'إذا فاز المصرفي بـ "طبيعية"، يفوز تنين المصرفي؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents50':
        'إذا فاز اللاعب بـ "طبيعية"، يفوز تنين اللاعب؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents51':
        'إذا لم يحصل المصرفي على "طبيعي"، الفرق بين نقاط المصرفي ونقاط اللاعب هو N، إذا كانت N = 4~9، يفوز "تنين المصرفي";',
    'zr_cp_footer_menu_zr_zrtext_3_contents52':
        'إذا لم يحصل اللاعب على "طبيعي"، الفرق بين نقاط اللاعب ونقاط المصرفي هو N، إذا كانت N = 4~9، يفوز "تنين اللاعب";',
    'zr_cp_footer_menu_zr_zrtext_3_contents53':
        'تعني "طبيعية" أن مجموع البطاقتين الأوليتين هو 8 أو 9؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents54':
        'تشير "غير الطبيعية" إلى جميع الحالات الأخرى، راجع جدول المدفوعات لمزيد من التفاصيل.',
    'zr_cp_footer_menu_zr_zrtext_3_contents55': '16. سوبر تعادل',
    'zr_cp_footer_menu_zr_zrtext_3_contents56':
        'إذا كان هناك تعادل بين المصرفي واللاعب، فهناك 10 خيارات من سوبر تعادل (تعادل 0~تعادل 9)؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents57':
        'مثال: إذا كانت نتيجة البطاقات بين المصرفي واللاعب في اللعبة هي 0، فإن من يراهن على "سوبر تعادل 0" سيفوز.',
    'zr_cp_footer_menu_zr_zrtext_3_contents58': '17. كبير & صغير',
    'zr_cp_footer_menu_zr_zrtext_3_contents59':
        'يتم تحديد الفائز بناءً على إجمالي عدد البطاقات التي تم فتحها: 4 بطاقات تعتبر صغيرة، 5 أو 6 بطاقات تعتبر كبيرة؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents60':
        'إذا تم فتح 4 بطاقات، يفوز الصغير؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents61':
        'إذا تم فتح 5 بطاقات، يفوز الكبير؛',
    'zr_cp_footer_menu_zr_zrtext_3_contents62':
        'إذا تم فتح 6 بطاقات، يفوز الكبير.',
