    'zr_cp_footer_menu_zr_zrtext_4_contents26': 'Tigre pequeno',
    'zr_cp_footer_menu_zr_zrtext_4_contents27': '1:22',
    'zr_cp_footer_menu_zr_zrtext_4_contents28': 'par de tigre',
    'zr_cp_footer_menu_zr_zrtext_4_contents29':
        'Calcule o par da banca, o par do jogador e enfrente a mesma carta 1:100',
    'zr_cp_footer_menu_zr_zrtext_4_contents30':
        'Par de banqueiros e jogadores de jogos de azar 1:20',
    'zr_cp_footer_menu_zr_zrtext_4_contents31':
