    'zr_cp_footer_menu_zr_zrtext_4_contents32': 'par de tigre',
    'zr_cp_footer_menu_zr_zrtext_4_contents33': '1:40',
    'zr_cp_footer_menu_zr_zrtext_4_contents34':
        'Principais cartas do banqueiro e principais cartas do jogador',
    'zr_cp_footer_menu_zr_zrtext_4_contents35': '1:4',
    'zr_cp_footer_menu_zr_zrtext_4_contents36': 'Tianpai',
    'zr_cp_footer_menu_zr_zrtext_4_contents37': '1:1:6',
    'zr_cp_footer_menu_zr_zrtext_4_contents38': 'Dragão e Tigre',
    'zr_cp_footer_menu_zr_zrtext_4_contents39': '1:1',
    'zr_cp_footer_menu_zr_zrtext_4_contents40':
        'Caso haja empate entre dragão e tigre, metade da aposta será reembolsada.',
    'zr_cp_footer_menu_zr_zrtext_4_contents41': 'dragão e tigre',
    'zr_cp_footer_menu_zr_zrtext_4_contents42': '1:8',
    'zr_cp_footer_menu_zr_zrtext_4_contents43': 'super seis',
    'zr_cp_footer_menu_zr_zrtext_4_contents44':
        'Se a banca ganhar com duas cartas e 6 pontos, as probabilidades são de 12 vezes',
    'zr_cp_footer_menu_zr_zrtext_4_contents45':
        'Se a banca ganhar com três cartas e 6 pontos, as probabilidades são de 20 vezes',
    'zr_cp_footer_menu_zr_zrtext_4_contents46': 'Longo Bao',
    'zr_cp_footer_menu_zr_zrtext_4_contents47':
        'Se os cartões estiverem empatados, o principal será reembolsado.',
    'zr_cp_footer_menu_zr_zrtext_4_contents48': 'A carta de exemplo ganha 1:1',
    'zr_cp_footer_menu_zr_zrtext_4_contents49':
        'Ganhe 4 pontos com cartas incomuns 1:1',
    'zr_cp_footer_menu_zr_zrtext_4_contents50':
        'Ganhe 5 pontos com cartas incomuns 1:2',
    'zr_cp_footer_menu_zr_zrtext_4_contents51':
        'Ganhe 6 pontos com cartas incomuns 1:3',
    'zr_cp_footer_menu_zr_zrtext_4_contents52':
        'Ganhe 7 pontos com cartas incomuns 1:5',
    'zr_cp_footer_menu_zr_zrtext_4_contents53':
        'Ganhe 8 pontos com cartas incomuns 1:10',
    'zr_cp_footer_menu_zr_zrtext_4_contents54':
        'Ganhe 9 pontos com cartas incomuns 1:30',
    'zr_cp_footer_menu_zr_zrtext_4_contents55': 'super sorteio',
    'zr_cp_footer_menu_zr_zrtext_4_contents56': 'super sorteio（0）1:125',
    'zr_cp_footer_menu_zr_zrtext_4_contents57': 'super sorteio（1）1:180',
    'zr_cp_footer_menu_zr_zrtext_4_contents58': 'super sorteio（2）1:190',
    'zr_cp_footer_menu_zr_zrtext_4_contents59': 'super sorteio（3）1:170',
    'zr_cp_footer_menu_zr_zrtext_4_contents60': 'super sorteio（4）1:100',
    'zr_cp_footer_menu_zr_zrtext_4_contents61': 'super sorteio（5）1:90',
    'zr_cp_footer_menu_zr_zrtext_4_contents62': 'super sorteio（6）1:40',
    'zr_cp_footer_menu_zr_zrtext_4_contents63': 'super sorteio（7）1:70',
    'zr_cp_footer_menu_zr_zrtext_4_contents64': 'super sorteio（8）1:70',
