    'zr_cp_footer_menu_zr_zrtext_4_contents67': '大1:0:5',
    'zr_cp_footer_menu_zr_zrtext_4_contents68': '小1:1:5',
    'zr_cp_footer_menu_zr_zrtext_5_0':
        '8 डेक कार्ड (जोकर को छोड़कर, कुल 416 कार्ड) का उपयोग करें जो सबसे लोकप्रिय हैं। अद्वितीय कार्ड वितरण नियम जीवन की तरह हैं, चाहे कोई भी स्थिति हो, यदि आप निवेश करते हैं, तो आपके पास हमेशा वापस आने का मौका होता है।',
    'zr_cp_footer_menu_zr_zrtext_5_1': '"सीधा मार" सुविधा का स्पष्टीकरण',
    'zr_cp_footer_menu_zr_zrtext_5_2':
        'जब मुख्य खेल में कोई दौर दिखाया जाता है',
    'zr_cp_footer_menu_zr_zrtext_5_3':
        'यह दर्शाता है कि खिलाड़ी या बैंकर बिना किसी अतिरिक्त कार्ड के सीधे प्रतिद्वंद्वी को हरा देता है',
    'zr_cp_footer_menu_zr_zrtext_6_0':
        'कुछ खेल मोडों में वर्तमान शू में लगाई जाने वाली शर्तों की संख्या पर प्रतिबंध हो सकता है। कृपया गेम के भीतर संबंधित निर्देश देखें।',
    'zr_cp_footer_menu_zr_zrtext_6_1':
        'टेबल सीमा मुख्य खेल मोड के लिए न्यूनतम और अधिकतम शर्त सीमा है।',
    'zr_cp_footer_menu_zr_zrtext_6_2':
        'जब डीलर कार्ड खोलता है, तो कभी-कभी सिस्टम स्थिति को पहचानने में विफल हो सकता है। इस स्थिति में, डीलर सिस्टम को सही ढंग से पहचानने के लिए पुन: प्रयास करेगा (यदि कोई खराबी पाई जाती है, तो संबंधित सभी दांव रद्द कर दिए जाएंगे)।',
    'zr_cp_footer_menu_zr_zrtext_6_3':
        'यदि खेल के दौरान, नेटवर्क या तकनीकी खराबी के कारण खेल सही ढंग से पूरा नहीं हो सका, तो सिस्टम सभी दांवों को रद्द कर देगा और खिलाड़ियों को दांव की गई राशि वापस कर देगा।',
    'zr_cp_footer_menu_zr_zrtext_7_0': 'बैंकर के दो कार्डों की कुल संख्या',
    'zr_cp_footer_menu_zr_zrtext_7_1':
        'जब मुख्य खेल में कोई दौर दिखाया जाता है',
    'zr_cp_footer_menu_zr_zrtext_7_2': 'या',
    'zr_cp_footer_menu_zr_zrtext_7_3': '，खिलाड़ी की जीत का संकेत देता है',
    'zr_cp_footer_menu_zr_zrtext_7_4': 'सीधे जीतने वाला राउंड क्या है?',
    'zr_cp_footer_menu_zr_zrtext_7_5':
        'खिलाड़ी (या बैंकर) के पहले 2 कार्ड 8/9 अंक प्राप्त करते हैं और प्रतिद्वंद्वी के खिलाफ सीधे जीतते हैं। न तो खिलाड़ी और न ही बैंकर को कोई अतिरिक्त कार्ड मिलता है।',
    'zr_cp_footer_menu_zr_zrtext_7_6':
        'खिलाड़ी (या बैंकर) के पहले 2 कार्ड 7 अंक प्राप्त करते हैं और प्रतिद्वंद्वी के 6 अंक के खिलाफ सीधे जीतते हैं। न तो खिलाड़ी और न ही बैंकर को कोई अतिरिक्त कार्ड मिलता है।',
    'zr_cp_footer_menu_zr_zrtext_7_7':
        'या बैंकर बिना किसी अतिरिक्त कार्ड के प्रतिद्वंद्वी को सीधे जीतता है;',
