    'zr_cp_footer_menu_zr_title': 'Hướng dẫn người thật',
    'zr_cp_footer_menu_zr_menus_0': 'luật chơi',
    'zr_cp_footer_menu_zr_menus_1': 'Ví dụ về thẻ cá cược',
    'zr_cp_footer_menu_zr_menus_2': 'Tính điểm',
    'zr_cp_footer_menu_zr_menus_3': 'Phán quyết chơi trò chơi',
    'zr_cp_footer_menu_zr_menus_4': 'bàn thanh toán',
    'zr_cp_footer_menu_zr_menus_5': 'Tính năng trò chơi',
    'zr_cp_footer_menu_zr_menus_6': 'Các biện pháp phòng ngừa',
    'zr_cp_footer_menu_zr_numbers_0': '0',
    'zr_cp_footer_menu_zr_numbers_1': '1',
    'zr_cp_footer_menu_zr_numbers_2': '2',
    'zr_cp_footer_menu_zr_numbers_3': '3',
    'zr_cp_footer_menu_zr_numbers_4': '4',
    'zr_cp_footer_menu_zr_numbers_5': '5',
    'zr_cp_footer_menu_zr_numbers_6': '6',
    'zr_cp_footer_menu_zr_numbers_7': '7',
    'zr_cp_footer_menu_zr_numbers_8': '8',
    'zr_cp_footer_menu_zr_numbers_9': '9',
    'zr_cp_footer_menu_zr_numbers_10': '10',
    'zr_cp_footer_menu_zr_point': 'dấu chấm',
    'zr_cp_footer_menu_zr_zrtext_0_0':
        'Sử dụng 8 bộ bài (không bao gồm vua lớn và vua nhỏ), tổng cộng 416 lá bài;',
    'zr_cp_footer_menu_zr_zrtext_0_1':
        '“Người chơi” và “Nhà cái” mỗi người chia hai lá bài, đầu tiên là “người chơi” và sau đó là “nhà cái” (thứ tự mở bài cũng giống nhau). Nếu ván đầu tiên không có người thắng thì đánh theo “luật đánh bài”, mỗi người chơi sẽ được chia tối đa 1 lá bài quyết định thắng thua;',
    'zr_cp_footer_menu_zr_zrtext_0_2':
        'Nếu nhà cái nào đạt được 8 hoặc 9 điểm (tự nhiên thắng), trò chơi sẽ được giải quyết bằng 4 lá bài đầu tiên và không được đánh bạc nữa;',
    'zr_cp_footer_menu_zr_zrtext_0_3':
        'Cuối cùng, tổng giá trị của Người chơi và Nhà cái là tỷ lệ một chữ số.',
    'zr_cp_footer_menu_zr_zrtext_1_title':
        '"Sau khi chủ ngân hàng và người chơi rút bài ở vòng đầu tiên, họ sẽ xác định xem họ có cần rút bài hay không. Đánh giá trước."',
    'zr_cp_footer_menu_zr_zrtext_1_title1':
        'Khi rảnh rỗi, bạn có thể phán xét lại chủ ngân hàng. Xem bảng dưới đây để biết chi tiết:"',
    'zr_cp_footer_menu_zr_zrtext_1_title2': 'Nhà cái rút bài',
    'zr_cp_footer_menu_zr_zrtext_1_contents0':
        'Tổng số điểm của hai lá bài của người chơi',
    'zr_cp_footer_menu_zr_zrtext_1_contents1': 'Phải rút bài',
    'zr_cp_footer_menu_zr_zrtext_1_contents2': 'Không được phép rút thẻ',
    'zr_cp_footer_menu_zr_zrtext_1_contents3':
        'Thẻ ví dụ xác định chiến thắng hay thất bại',
    'zr_cp_footer_menu_zr_zrtext_1_contents4': 'Phải rút bài',
    'zr_cp_footer_menu_zr_zrtext_1_contents5':
        'Nếu giá trị của lá bài thứ ba mà Người chơi thắng được là 8 điểm thì Nhà cái không được phép rút bất kỳ lá bài nào.',
    'zr_cp_footer_menu_zr_zrtext_1_contents6':
        'Nếu người chơi rút lá bài thứ 3 có giá trị lá bài là 0, 1, 8 hoặc 9 điểm thì nhà cái không được rút lá bài đó.',
    'zr_cp_footer_menu_zr_zrtext_1_contents7':
        'Nếu người chơi rút lá bài thứ 3 có giá trị lá bài là 0, 1, 2, 3, 8 hoặc 9 điểm thì nhà cái không được rút lá bài đó.',
    'zr_cp_footer_menu_zr_zrtext_1_contents8':
        'Nếu người chơi rút lá bài thứ 3 có giá trị là 6 hoặc 7 thì nhà cái phải rút lá bài đó',
    'zr_cp_footer_menu_zr_zrtext_2_contents0':
        'A-9 điểm, số điểm được xác định theo giá trị lá bài, trong đó A tương ứng với 1 điểm',
    'zr_cp_footer_menu_zr_zrtext_2_contents1':
        '10 hoặc J hoặc Q hoặc K là 0 điểm',
    'zr_cp_footer_menu_zr_zrtext_2_contents2': 'ví dụ',
    'zr_cp_footer_menu_zr_zrtext_2_contents3': '+',
    'zr_cp_footer_menu_zr_zrtext_3_contents0':
        '1. Nhà cái & Người chơi & Hòa hợp',
    'zr_cp_footer_menu_zr_zrtext_3_contents1':
        'Nếu điểm của nhà cái lớn hơn điểm của người chơi thì người đặt cược vào “nhà cái” sẽ được thưởng.',
    'zr_cp_footer_menu_zr_zrtext_3_contents2': 'ví dụ',
    'zr_cp_footer_menu_zr_zrtext_3_contents3': 'Nhân viên ngân hàng:',
    'zr_cp_footer_menu_zr_zrtext_3_contents4': 'Người chơi:',
    'zr_cp_footer_menu_zr_zrtext_3_contents5':
        'Nếu điểm của người chơi lớn hơn điểm của nhà cái thì người chơi đặt cược vào “người chơi” sẽ được thưởng.',
    'zr_cp_footer_menu_zr_zrtext_3_contents6':
        'Nếu nhà cái và người chơi bằng điểm thì người đặt cược “hòa” sẽ nhận được thưởng.',
    'zr_cp_footer_menu_zr_zrtext_3_contents7':
        '2. Cặp nhà cái và cặp người chơi',
    'zr_cp_footer_menu_zr_zrtext_3_contents8':
        'Trong trò chơi hiện tại, hai lá bài đầu tiên của nhà cái hoặc người chơi (chỉ số hoặc chữ Người mẹ (không phân biệt màu da, trang phục) là cặp con trai;',
    'zr_cp_footer_menu_zr_zrtext_3_contents9': 'Chủ ngân hàng/Người chơi:',
    'zr_cp_footer_menu_zr_zrtext_3_contents10':
        'Hai lá bài đầu tiên của người chia bài là một đôi, là một đôi của người chia bài. Hai lá bài đầu tiên của người chơi là một đôi, là đôi của người chơi;',
    'zr_cp_footer_menu_zr_zrtext_3_contents11':
        'Khi xuất hiện một cặp, hãy đặt cược vào “cặp nhà cái” hoặc “cặp người chơi” để nhận phần thưởng với tỷ lệ cược tương ứng.',
    'zr_cp_footer_menu_zr_zrtext_3_contents12': '3. Cặp nào cũng được',
    'zr_cp_footer_menu_zr_zrtext_3_contents13':
        'Đề cập đến hai lá bài đầu tiên của Nhà cái hoặc Người chơi dưới dạng một cặp (xem Cặp nhà cái & Cặp người chơi để biết chi tiết);',
    'zr_cp_footer_menu_zr_zrtext_3_contents14':
        'Bất kể cặp nhà cái hay cặp người chơi xuất hiện, người đặt cược vào “cặp bất kỳ” đều sẽ nhận được phần thưởng.',
    'zr_cp_footer_menu_zr_zrtext_3_contents15': '4. Cặp đôi hoàn hảo',
    'zr_cp_footer_menu_zr_zrtext_3_contents16':
        'Có nghĩa là hai lá bài đầu tiên của Banker hoặc Player là cặp (xem Banker Pair & Player Pair để biết chi tiết), đồng thời đáp ứng các điều kiện về cùng chất và màu;',
    'zr_cp_footer_menu_zr_zrtext_3_contents17':
        'Bất kể nhà cái hay người chơi có cặp hoàn hảo thì ai đặt cược vào “cặp hoàn hảo” đều sẽ nhận được phần thưởng.',
    'zr_cp_footer_menu_zr_zrtext_3_contents18': '5. Siêu đúng',
    'zr_cp_footer_menu_zr_zrtext_3_contents19':
        '4 lá bài đầu tiên chứa từ hai lá bài giống nhau trở lên (không phân biệt chất).',
    'zr_cp_footer_menu_zr_zrtext_3_contents20': '6. Rồng 7',
    'zr_cp_footer_menu_zr_zrtext_3_contents21':
        'Nhà cái thắng với 3 lá bài và 7 điểm.',
    'zr_cp_footer_menu_zr_zrtext_3_contents22': '7. Gấu trúc 8',
    'zr_cp_footer_menu_zr_zrtext_3_contents23':
        'Nhà cái thắng 8 điểm với 3 lá bài.',
    'zr_cp_footer_menu_zr_zrtext_3_contents24': '8. Hổ lớn & Hổ nhỏ',
    'zr_cp_footer_menu_zr_zrtext_3_contents25':
        'Người chia bài thắng ba lá bài 6 điểm và trở thành hổ lớn;',
    'zr_cp_footer_menu_zr_zrtext_3_contents26':
        'Người chia bài thắng với hai lá bài 6 điểm và trở thành con hổ nhỏ.',
    'zr_cp_footer_menu_zr_zrtext_3_contents27': '9.Tiger và',
    'zr_cp_footer_menu_zr_zrtext_3_contents28':
        'Banker và Player lần lượt bằng 6 điểm.',
    'zr_cp_footer_menu_zr_zrtext_3_contents29': '10. Cặp Hổ',
    'zr_cp_footer_menu_zr_zrtext_3_contents30':
        'Theo kết quả 4 lá bài đầu tiên của nhà cái và người chơi, nếu gặp 1 trong 3 kết quả sau sẽ thu được tỷ lệ cược khác nhau:',
    'zr_cp_footer_menu_zr_zrtext_3_contents31':
        'Cặp ngân hàng và cặp người chơi được tính toán và chúng có cùng một lá bài;',
    'zr_cp_footer_menu_zr_zrtext_3_contents32':
        'Lập kế hoạch cho cặp ngân hàng và cặp của người chơi;',
    'zr_cp_footer_menu_zr_zrtext_3_contents33':
        'Cặp chủ ngân hàng hoặc người chơi cờ bạc；',
    'zr_cp_footer_menu_zr_zrtext_3_contents34':
        'Cược sẽ không được hoàn trả trong trường hợp hòa.',
    'zr_cp_footer_menu_zr_zrtext_3_contents35':
        '11. Trang Thiên Phái & Tiên Thiên Phái',
    'zr_cp_footer_menu_zr_zrtext_3_contents36':
        'Nếu hai lá bài đầu tiên của người chia bài có tổng điểm là 8 hoặc 9 điểm, người chia bài thắng thì người đặt cược vào “lá bài Zhuang Tian” sẽ được thưởng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents37':
        'Nếu hai lá bài đầu tiên của người chơi có tổng điểm là 8 hoặc 9 điểm và người chơi thắng thì người chơi đặt cược vào “thẻ người chơi” sẽ được thưởng.',
    'zr_cp_footer_menu_zr_zrtext_3_contents38': '12.Tian Pai',
    'zr_cp_footer_menu_zr_zrtext_3_contents39':
        'Nhà cái hoặc người chơi thắng nếu hai lá bài đầu tiên của nhà cái hoặc người chơi có tổng điểm là 8 hoặc 9 điểm.',
    'zr_cp_footer_menu_zr_zrtext_3_contents40': '13. Rồng Hổ Hòa Hợp',
    'zr_cp_footer_menu_zr_zrtext_3_contents41':
        'Nếu lá bài đầu tiên của người chia bài có giá trị cao hơn lá bài đầu tiên của người chơi (10, J, Q và K lần lượt là 10, 11, 12 và 13 điểm) thì rồng thắng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents42':
        'Nếu lá bài đầu tiên của người chơi có giá trị cao hơn lá bài đầu tiên của nhà cái (10, J, Q, K lần lượt là 10, 11, 12 và 13 điểm) thì hổ thắng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents43':
        'Lá bài đầu tiên của nhà cái và người chơi có cùng số điểm (10, J, Q, K lần lượt là 10, 11, 12 và 13 điểm), là tổng của rồng và hổ.',
    'zr_cp_footer_menu_zr_zrtext_3_contents44': '14.Siêu Sáu',
    'zr_cp_footer_menu_zr_zrtext_3_contents45':
        'Cá cược có sẵn ở cả hai chế độ không có hoa hồng và không có hoa hồng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents46':
        'Khi người chia bài chưa rút bài, điểm và đơn vị là 6, điểm quá nhàn rỗi thì tỷ lệ cược là 12 lần;',
    'zr_cp_footer_menu_zr_zrtext_3_contents47':
        'Khi người chia bài chưa rút bài, điểm và đơn vị là 6, điểm quá nhàn rỗi thì tỷ lệ cược là 20 lần;',
    'zr_cp_footer_menu_zr_zrtext_3_contents48':
        '15. Trang Long Bảo & Tiên Long Bảo',
    'zr_cp_footer_menu_zr_zrtext_3_contents49':
        'Nếu chủ ngân hàng thắng bằng lá bài mẫu thì bảo bối rồng của chủ ngân hàng sẽ thắng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents50':
        'Nếu Xian thắng bằng lá bài mẫu thì Xian Long Bao thắng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents51':
        'Thẻ không ngoại lệ của chủ ngân hàng, điểm của chủ ngân hàng - điểm của người chơi = N, nếu N = 4 ~ 9 thì Zhuang Longbao thắng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents52':
        'Người chơi là thẻ không ngoại lệ, điểm người chơi - điểm ngân hàng = N, nếu N = 4 ~ 9, kho báu rồng của người chơi thắng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents53':
        'Định nghĩa lá bài ví dụ: Hai lá bài đầu tiên có kết quả là 8 hoặc 9 điểm;',
    'zr_cp_footer_menu_zr_zrtext_3_contents54':
        'Định nghĩa về thẻ không ngoại lệ: Tất cả các tình huống không phải là thẻ ngoại lệ, hãy xem bảng thanh toán để biết chi tiết.',
    'zr_cp_footer_menu_zr_zrtext_3_contents55': '16.Siêu hòa hợp',
    'zr_cp_footer_menu_zr_zrtext_3_contents56':
        'Khi Nhà cái và Người chơi hòa nhau, điểm hòa bao gồm "và 0 ~ và 9", tổng cộng có mười điểm siêu hòa;',
    'zr_cp_footer_menu_zr_zrtext_3_contents57':
        'Ví dụ: trong trò chơi, khi kết quả bài của người chia bài và người chơi đều bằng 0 thì người đặt cược “Siêu và 0” sẽ thắng;',
    'zr_cp_footer_menu_zr_zrtext_3_contents58': '17. Kích thước',
    'zr_cp_footer_menu_zr_zrtext_3_contents59':
        'Dựa trên tổng số quân bài được rút ra cuối cùng, 4 quân bài được coi là nhỏ và 5 hoặc 6 quân bài được coi là cao.',
    'zr_cp_footer_menu_zr_zrtext_3_contents60':
        'Cuối cùng, 4 lá bài được rút trong trò chơi này và người chơi đã thắng với tỷ số chênh lệch nhỏ.',
    'zr_cp_footer_menu_zr_zrtext_3_contents61':
        'Cuối cùng, 5 lá bài được rút ra trong trò chơi này, đó là một chiến thắng đậm.',
    'zr_cp_footer_menu_zr_zrtext_3_contents62':
        'Cuối cùng, 6 lá bài được rút ra trong trò chơi này, đó là một chiến thắng đậm.',
    'zr_cp_footer_menu_zr_zrtext_4_contents0':
        'Trong trò chơi Baccarat, lối chơi Baccarat và lối chơi Baccarat miễn phí được cung cấp. Luật chơi của hai trò chơi này giống nhau nhưng cách thức đặt cược của nhà cái lại khác nhau:',
    'zr_cp_footer_menu_zr_zrtext_4_contents1': 'Baccarat',
    'zr_cp_footer_menu_zr_zrtext_4_contents2': 'Vật phẩm cá cược',
    'zr_cp_footer_menu_zr_zrtext_4_contents3': 'Tỷ lệ cược',
    'zr_cp_footer_menu_zr_zrtext_4_contents4': 'Người chơi',
