    'zr_cp_footer_menu_zr_zrtext_4_contents40':
        'Nếu rồng và hổ hòa, một nửa số tiền đặt cược sẽ được hoàn lại.',
    'zr_cp_footer_menu_zr_zrtext_4_contents41': 'rồng và hổ',
