    'zr_cp_footer_menu_zr_zrtext_4_contents44':
        'Nếu nhà cái thắng với 2 quân bài và 6 điểm thì tỷ lệ cược là 12 lần',
    'zr_cp_footer_menu_zr_zrtext_4_contents45':
        'Nếu nhà cái thắng với 3 lá bài và 6 điểm thì tỷ lệ cược là 20 lần',
    'zr_cp_footer_menu_zr_zrtext_4_contents46': 'Long Bảo',
    'zr_cp_footer_menu_zr_zrtext_4_contents47':
        'Nếu bài hòa thì tiền gốc sẽ được hoàn lại.',
    'zr_cp_footer_menu_zr_zrtext_4_contents48': 'Lá bài ví dụ thắng 1:1',
