    'zr_cp_footer_menu_zr_zrtext_4_contents68': 'Bé nhỏ 1:1:5',
    'zr_cp_footer_menu_zr_zrtext_5_0':
        'Sử dụng 8 bộ bài phổ biến nhất (tổng cộng 416 lá bài không bao gồm vua và vua). Luật cờ bạc độc đáo, giống như cuộc sống, dù mất bao lâu, chỉ cần bạn đầu tư thì luôn có cơ hội quay lại.',
    'zr_cp_footer_menu_zr_zrtext_5_1': 'Mô tả chức năng "Direct Kill"',
    'zr_cp_footer_menu_zr_zrtext_5_2':
        'Khi một trò chơi nào đó trên đường được hiển thị dưới dạng',
    'zr_cp_footer_menu_zr_zrtext_5_3':
        'Đại diện cho người chơi trong bảng Hoặc người chia bài trực tiếp hạ gục đối thủ mà không ra tay;',
    'zr_cp_footer_menu_zr_zrtext_6_0':
        'Một số phương pháp chơi có thể có những hạn chế về số lượng cược có thể đặt trong các trò chơi được chỉ định của phần khởi động này. Vui lòng kiểm tra các mẹo trong trò chơi có liên quan để biết chi tiết.',
    'zr_cp_footer_menu_zr_zrtext_6_1':
        'Giới hạn màu đỏ của bàn chơi là giới hạn màu đỏ tối thiểu và tối đa cho lối chơi chính của bàn trò chơi này.',
    'zr_cp_footer_menu_zr_zrtext_6_2':
        'Khi người chia bài mở bài, đôi khi hệ thống không thể nhận biết được tình huống. Lúc này, nhà cái sẽ cố gắng nhận dạng lại hệ thống cho đến khi hệ thống nhận diện chính xác (nếu có yếu tố sai sót, tất cả các lệnh/khoản thanh toán liên quan sẽ bị hủy).',
    'zr_cp_footer_menu_zr_zrtext_6_3':
        'Nếu trò chơi không thể hoàn thành bình thường do lỗi mạng của nền tảng trò chơi trong khi chơi, hệ thống sẽ hủy toàn bộ trò chơi và hoàn trả tiền gốc cá cược của người chơi.',
    'zr_cp_footer_menu_zr_zrtext_7_0':
        'Tổng số điểm của hai lá bài của nhà cái',
    'zr_cp_footer_menu_zr_zrtext_7_1':
        'Khi một trò chơi nào đó trên đường được hiển thị dưới dạng',
    'zr_cp_footer_menu_zr_zrtext_7_2': 'hoặc',
    'zr_cp_footer_menu_zr_zrtext_7_3': '，Đại diện cho người chơi trong bảng',
    'zr_cp_footer_menu_zr_zrtext_7_4': 'Trò chơi tiêu diệt trực tiếp là gì?',
    'zr_cp_footer_menu_zr_zrtext_7_5':
        '2 lá bài đầu tiên của người chơi (hoặc nhà cái) trực tiếp thắng đối thủ với 8/9 điểm, cả người chơi và nhà cái đều không nhận được lá bài phụ nào.',
    'zr_cp_footer_menu_zr_zrtext_7_6':
        '2 lá bài đầu tiên của người chơi (hoặc nhà cái) trực tiếp giành được 6 điểm của đối phương với 7 điểm, cả người chơi và nhà cái đều không nhận được điểm nào.',
    'zr_cp_footer_menu_zr_zrtext_7_7':
